import{_ as a,o as t,c as o,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"采佩什","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/采佩什.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/采佩什.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/采佩什.md"};function i(l,e,c,b,_,p){return t(),o("div",null,[...e[0]||(e[0]=[r("h1",{id:"采佩什",tabindex:"-1"},[n("采佩什 "),r("a",{class:"header-anchor",href:"#采佩什","aria-label":'Permalink to "采佩什"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌037")])])],-1),s('<h1 id="采佩什-1" tabindex="-1">采佩什 <a class="header-anchor" href="#采佩什-1" aria-label="Permalink to &quot;采佩什&quot;">​</a></h1><p>I采佩什<br> 科技本质<br> A+4000<br> 分类：长枪<br> 武器伤害：27L+2附加<br> 武器特性：【长柄】【双手】【破甲1】【格挡2】<br> 伤害类型：物理-穿刺<br> 体积：10<br> 描述：该武装的外形是一把金色的巨型长枪，由黑白金三色组成，金色枪头全长125cm，尖端呈剑型，靠近长杆的枪头末端形似菱形，枪头最宽处约75cm，枪脊高耸，色银白，绑有6条精金制束缚带，在漆黑的主手枪杆方面有6条弧形螺旋状黄金护手，枪杆全长260cm，杆尾为菱形金刺，约10cm。<br> 这把武装搭载的异灵（Sprite）是名为『穿刺公（Vlad）』的类人脑智能生命系统，其具有绝对的傲气与暴虐，在持有这把武器时，持有者会不由自主地因武器的同频而受到情绪上的影响，因此承受2点不可减免且永久存在不可消除的精神束缚点数，变得更加暴虐与热爱世间的一切，这矛盾的二元情绪即非交错亦非相悖，而是交融合一，产生『摧毁世间一切所爱之物』的暴虐之爱，而爱的对象则是『世间一切』，由此共振产生的异能便是『穿刺之爱（Perforating-Amor）』，特殊的是，因该武装的异灵与异能限制，仅能施展造成物理-穿刺伤害的攻击。<br> 该武装的主题是被主观扭曲的『爱』，虽然该武装的内核扭曲而抽象，但其异能『穿刺之爱』却是拥有着罕见大规模杀伤性能力的空间系异能，最初融合该异能时，『穿刺公』强烈地『想要将爱带给目光所及之处』的扭曲情感使得原异能的空间能力产生了强烈的变化，这一部分被称为『发现之爱（Amor inventionis）』，直接的表现为，武装的持有者可以直接锁定自身敏感范围内的一个目标并且如对方在自身触及范围内般进行攻击，这次攻击会向前戳刺，并且在身前半米处撕裂空间消失，消失的长枪将刺破目标身下的空间，自下而上穿刺攻击敌人，这代表着，以该武器进行的攻击皆带有C级命运来源的传送攻击能力，可以在敏感范围内如自身触及般进行近战攻击。<br> 除了『发现之爱』以外，『穿刺之爱』还拥有着名为『独占之爱（Exclusive amor）』与『毁灭之爱（Destruendi amor）』的部分。<br> 『独占之爱（Exclusive amor）』是『爱』这一核心概念中的，『对于所爱之物绝不让其逃离』的情感，这种强烈的情感异化了原异能的控制能力，使得以该武器进行的攻击都将附带有伤害等量的A级命运来源束缚点数，反射豁免。<br> 『毁灭之爱（Destruendi amor）』是『爱』这一核心概念中的，『对于所爱之物倾尽全心全意』的情感，这种强烈的恶意使得这把武器进行的攻击获得了【8加骰】与【幻灭】特性。<br> 而『发现』『独占』『毁灭』这三者以『爱』而生的异能部分共同结合，在爱世间万物的虐杀者『穿刺公（Vald）』的共鸣之下，才造就了『穿刺之爱（Perforating-Amor』这一常态复合型异能，其完全由『穿刺公（Vald）』驱动，一轮一次，当你以标准动作进行攻击后，『穿刺公』会自动锁定你敏感范围内的所有敌人，你需要投掷一次不附带技艺的标准动作攻击，而那次攻击出目将作为锁定全部敌人的异能伤害保留，那之后，所有被锁定的敌人身下都将出现一只体积10的黄金枪尖，自下而上地穿刺所有人，这次攻击正常附带该武装拥有的所有效果，无论如何，只要被该武器进行的攻击击杀，死者的身体将立即被自下而上的金色长枪刺穿，枪尖从其口中钻出，并有另外2~4把长枪刺出，将其固定在半空。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const f=a(d,[["render",i]]);export{h as __pageData,f as default};
